testcases.ir:
define i8 @test_unsigned_all_same(i32 %a, i32 %b) {
  %res = call i8 @llvm.ucmp.i8.i32(i32 %a, i32 %b)
  switch i8 %res, label %bb1 [
    i8 -1, label %bb1
    i8 0, label %bb1
    i8 1, label %bb1
  ]

bb1:
  ret i8 1
}

